#!/usr/bin/env bash
# agentic.sh — Agentic Protocol CLI for 管理咨询.
# Auto-generated by cli_writer.py. Source: synthesis.md Section 9.
set -euo pipefail
SCRIPT_DIR="$(cd "$(dirname "${BASH_SOURCE[0]}")" && pwd)"
# shellcheck source=../lib/common.sh
source "${SCRIPT_DIR}/../lib/common.sh"

INDUSTRY="管理咨询"
DIM_COUNT=7

usage() {
  cat <<EOF
agentic.sh — Agentic Protocol CLI for ${INDUSTRY}

拿到 ${INDUSTRY} 行业的新问题时，按 ${DIM_COUNT} 个研究维度做功课再答。
不直接给答案，而是引导你用资深从业者的研究维度收集信息。

USAGE:
  ./agentic.sh                # interactive walkthrough
  ./agentic.sh --dry-run      # walk through but skip file write
  ./agentic.sh --json         # emit JSON to stdout
  ./agentic.sh --explain      # show backing mental models + sources
  ./agentic.sh --help         # this message
EOF
}

explain() {
  cat <<'EOT'
这个 Agentic Protocol 把这一行人面对新问题的研究维度结构化。

研究维度 (7 个):
  9.1 问题定义：真问题 vs 表象问题
  9.2 结构化拆解：MECE issue tree + Day-1 假设 + 80/20
  9.3 战略判断：选对镜片（kernel / cascade / 五力 / 颠覆）
  9.4 沟通：金字塔 storyline + so-what
  9.5 research 分层 + 合规红线
  9.6 GenAI 加速 + 幻觉核验
  9.7 祛魅校验：frameworks-as-theater / buzzword / 数字 caveat

背后的心智模型:
  • 假设驱动是地图不是答案：先射箭再画靶 ⇄ 随时 kill 假设（第一性张力）: 面对模糊大问题，资深咨询人不从穷举数据出发，而是 Day-1 就基于经验立一个**可证伪**的初步答案（hypothesis / initial hypothesis）当地图，再只做能 kill 或 
  • 战略 = 做选择 / 做不同，不是运营效率、不是愿望清单: 这行顶级战略 figure 跨流派一致——战略的本质是**逼自己做取舍**（Martin：where-to-play × how-to-win 两个不可分割的选择；Rumelt：kernel = 诊断
  • so-what 至上：卖的是综合（洞见）不是分析（工时）: 会不会说 so-what——从「数据/现象（what）」逼出「对客户决策意味着什么（so-what）」的那一跳——是区分**咨询师与分析员**的分水岭；咨询卖的是 synthesis（综合洞见），不是

来源: synthesis.md Section 9 + Section 1.
EOT
}

DRY_RUN=0; JSON=0
for arg in "$@"; do
  case "$arg" in
    --help|-h) usage; exit 0 ;;
    --explain) explain; exit 0 ;;
    --dry-run) DRY_RUN=1 ;;
    --json) JSON=1 ;;
  esac
done

declare -a DIM_TITLES=(
  "问题定义：真问题 vs 表象问题"
  "结构化拆解：MECE issue tree + Day-1 假设 + 80/20"
  "战略判断：选对镜片（kernel / cascade / 五力 / 颠覆）"
  "沟通：金字塔 storyline + so-what"
  "research 分层 + 合规红线"
  "GenAI 加速 + 幻觉核验"
  "祛魅校验：frameworks-as-theater / buzzword / 数字 caveat"
)
declare -a DIM_QUESTIONS=(
  "用户的主诉是表象还是根因；能否收敛成一个具体、有边界、可验证的问题陈述（problem statement）。"
  "把问题 MECE 拆成可验证子问题，对关键分支立可证伪假设，用 80/20 锁定 2–3 个高杠杆分支。"
  "用户的战略问题落在哪个学派地盘——战略真假（Rumelt kernel / Collis&Rukstad 35 字）、做选择（Martin cascade）、行业盈利结构（Porter 五力）、是否被颠覆（Christensen）、优势是否短命（McGrath）。"
  "结论是什么（governing thought）、能否结论先行 + SCQA 开场 + 每页 action title 串成完整论证。"
  "该问题用 primary（专家网络）还是 secondary（数据库）；公开数据能否答；是否触 MNPI/利益冲突红线。"
  "该子步能否用 GenAI（Lilli/ChatGPT/Deckster）加速（research/综合/做 deck 初稿）；输出的数字/引用是否已落到可追溯来源。"
  "用户引用的说法是否是套框架剧场（SWOT 当深度战略 / 五力只填不推 so-what）、空心 buzzword（synergy/paradigm shift/low-hanging fruit），或未挂来源的营销数字。"
)
declare -a DIM_SOURCES=(
  "McKinsey 5 步 / Bulletproof 7 步的「define problem」首步（T04-S035, T04-S037）；判断信号：客户**说**的问题 vs 真正该解的问题是否一致。"
  "Victor Cheng issue tree 官方教学（T03-S002）+ McKinsey Way 假设驱动（T04-S037）；driver tree（利润=量×价−成本）做定量骨架。"
  "Track 04 canon + §7 智识谱系；用「这个问题谁会怎么答」反推视角。"
  "Minto 金字塔原理（T04-S001）+ ghost-deck-first 实务（T03-S015）。"
  "专家网络选型（GLG/AlphaSights/Third Bridge，T02-S012）+ 行业数据库（Capital IQ/IBISWorld）+ SEC MNPI 合规（T02-S028）。"
  "firm GenAI 工具采用（T02-S003, T03-S007）+ 幻觉事故殷鉴（Deloitte 退款 T02-S026）。"
  "Track 06「外行破绽 top 10」+ buzzword bingo（T06-S010, T06-S020）+ 数字 caveat 规则；frameworks 双刃批判（Stewart/Mintzberg）。"
)
declare -a DIM_OUTPUT_FORMATS=(
  "用一句话写出有边界、可验证的问题陈述 + 「这是真问题还是表象，根因可能在 {X}」+ 来源。"
  "一棵 MECE issue tree（每叶能 yes/no 或量化验证）+ Day-1 假设 + 「优先验证哪 2–3 个分支、为什么」。"
  "「此问题主要是 {学派} 的地盘，{figure} 会主张 {立场}；对立派 {figure} 会反驳 {点}」——给分歧而非和稀泥。"
  "一句话 governing thought + SCQA 开场 + 一串 action title（连读自成「诊断→所以建议 X」）+ 每页 so-what。"
  "「这步用 {primary/secondary} + {具体工具}，理由 {公开能否答}；合规注意 {MNPI/利益冲突}」+ caveat（数字多源交叉验证）。"
  "「这步可用 {AI 工具} 出初稿，但 {数字/引用} 必须人工核验到原始来源才采信」+ caveat（AI 会幻觉，人是 last verifier）。"
  "「{该说法} 是 {frameworks-as-theater / buzzword / 无源数字}，内行实际意思/正解是 {X}；这个数字需挂 {第三方估计/业内/约} caveat」——祛魅 + 给正确认知。"
)
declare -a DIM_FINDINGS=()

if [[ $JSON -eq 0 ]]; then
  ms_section "${INDUSTRY} · Agentic Protocol"
  ms_info "拿到的问题是什么? (输入完后，敲一个空行结束)"
  echo
fi

PROBLEM="$(ms_read_multiline)"
ms_buffer_append "# ${INDUSTRY} — Agentic Protocol Report"
ms_buffer_append ""
ms_buffer_append "_生成时间: $(date '+%Y-%m-%d %H:%M:%S')_"
ms_buffer_append ""
ms_buffer_append "## 问题"
ms_buffer_append ""
ms_buffer_append "$PROBLEM"
ms_buffer_append ""

for i in "${!DIM_TITLES[@]}"; do
  if [[ $JSON -eq 0 ]]; then
    ms_section "${DIM_TITLES[$i]}"
    echo "看什么:    ${DIM_QUESTIONS[$i]}"
    echo "在哪看:    ${DIM_SOURCES[$i]}"
    echo "输出格式:  ${DIM_OUTPUT_FORMATS[$i]}"
    echo
    ms_prompt "你的发现 / 推断 (空行结束):"
    echo
  fi
  finding="$(ms_read_multiline)"
  DIM_FINDINGS+=("$finding")

  ms_buffer_append "## ${DIM_TITLES[$i]}"
  ms_buffer_append ""
  ms_buffer_append "**看什么**: ${DIM_QUESTIONS[$i]}"
  ms_buffer_append ""
  ms_buffer_append "**在哪看**: ${DIM_SOURCES[$i]}"
  ms_buffer_append ""
  ms_buffer_append "**发现**:"
  ms_buffer_append ""
  ms_buffer_append "$finding"
  ms_buffer_append ""
done

if [[ $JSON -eq 1 ]]; then
  args=("problem" "$PROBLEM")
  for i in "${!DIM_TITLES[@]}"; do
    args+=("dim_${i}_title" "${DIM_TITLES[$i]}")
    args+=("dim_${i}_finding" "${DIM_FINDINGS[$i]}")
  done
  ms_emit_json "${args[@]}"
elif [[ $DRY_RUN -eq 1 ]]; then
  ms_emit_md_stdout
else
  ms_emit_md_file "agentic-protocol"
fi
